create table dirkspzm32.isi_rohstoff_materialart (
    sid          varchar2(2 char) not null enable,
    materialart  varchar2(20 char) not null enable,
    bezeichnung1 varchar2(30 char),
    dichte       number(*, 5)
);

alter table dirkspzm32.isi_rohstoff_materialart
    add constraint pk_rohstoff_materialart primary key ( materialart )
        using index enable;


